urlset:

  {{ '/' | absurl }}


  {{ '/photography/' | absurl }}

{% for gallery in galleries %}
{% if gallery.listed %}

  {{ ('/photography/' + gallery.slug + '/') | absurl }}

{% endif %}
{% for photo in gallery.photos %}

  {{ ('/photography/' + gallery.slug + '/' + (photo.slug | bareslug) + '/') | absurl }}

{% endfor %}
{% endfor %}

  {{ '/blog/' | absurl }}

{% for post in posts %}

  {{ ('/blog/' + post.slug + '/') | absurl }}

{% endfor %}
{% for page in pages %}

  {{ ('/' + page.slug + '/') | absurl }}

{% endfor %}
{% if tag_pages.length %}

  {{ '/tags/' | absurl }}

{% for tp in tag_pages %}

  {{ ('/tags/' + tp.slug + '/') | absurl }}

{% endfor %}
{% endif %}
{% if location_pages.length %}

  {{ '/locations/' | absurl }}

{% for lp in location_pages %}

  {{ ('/locations/' + lp.slug + '/') | absurl }}

{% endfor %}
{% endif %}
